// ClaimSight — Eval Harness Data
// Pre-computed benchmark metrics for the eval dashboard. In production these
// would be generated by the CI-gated eval suite (Ragas + DeepEval + LLM-judge)
// run against the labeled claim corpus.

export interface EvalMetric {
  name: string;
  description: string;
  value: number;
  unit: "%" | "score" | "ms" | "$" | "ratio";
  baseline: number; // naive baseline for comparison
  target: number;
  category: "retrieval" | "extraction" | "vision" | "fraud" | "adjudication" | "system";
}

